"use client";

import React, { useState, useEffect } from "react";
import { Spinner, Button, Modal, ModalContent, ModalHeader, ModalBody, ModalFooter, Tooltip } from "@heroui/react";
import { useOrderStore } from "@/store/useOrderStore";
import { payOrder, getTodayOrders, cancelOrderAction, replaceOrderItemCode, refundOrderItem, refundFullOrder } from "./actions";
import { useAuthStore } from "@/store/useAuthStore";
import { toast } from "react-hot-toast";
import OrderDetailModal from "@/components/admin/modals/OrderDetailModal";
import { Eye, User as UserIcon, Plus, Usb, Loader2 } from "lucide-react";
import { getAllClients, createClient } from "../clients/actions";
import { formatCurrency } from "@/lib/formatters";
import { ThermalReceiptV2 } from "@/components/admin/receipt/ThermalReceiptV2";
import { useThermalPrinter } from "@/hooks/useThermalPrinter";
import { useWebUSBPrinter } from "@/hooks/useWebUSBPrinter";
import { generateOrderEscPos } from "@/lib/escpos";
import { useSettingsStore } from "@/store/useSettingsStore";

export default function CaisseContent() {
    const {
        currentOrder,
        setCurrentOrder,
        searchQuery,
        setSearchQuery,
    } = useOrderStore();
    const { user } = useAuthStore();

    const [isUpdating, setIsUpdating] = useState(false);
    const [allTodayOrders, setAllTodayOrders] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState<string>("Toutes");
    const [remise, setRemise] = useState<number>(0);
    const [montantRecu, setMontantRecu] = useState<number | string>("");
    const [selectedClientId, setSelectedClientId] = useState<number | null>(null);
    const [allClients, setAllClients] = useState<any[]>([]);
    const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
    const [orderForDetail, setOrderForDetail] = useState<any | null>(null);
    const [isCreatingClient, setIsCreatingClient] = useState(false);
    const [newClientName, setNewClientName] = useState("");
    const [newClientPhone, setNewClientPhone] = useState("");
    const [itemSuppliers, setItemSuppliers] = useState<Record<number, number>>({});
    const [printData, setPrintData] = useState<any>(null);
    const [lastReloadTime, setLastReloadTime] = useState<Date>(new Date());
    const { printToIframe } = useThermalPrinter();

    const settings = useSettingsStore();
    const webusb = useWebUSBPrinter();

    const handlePrint = async (data: any) => {
        // High Performance: WebUSB Direct Print
        if (webusb.connected) {
            try {
                const buffer = generateOrderEscPos(data, settings);
                await webusb.print(buffer);
                toast.success(`Impression USB : #${data.orderNumber}`);
                return;
            } catch (error) {
                console.error("USB Print failed:", error);
                toast.error("├ëchec USB, basculement en mode standard...");
            }
        }

        // Standard Fallback: hidden iframe rendering
        setTimeout(() => {
            const printContent = document.getElementById('thermal-receipt-source');
            if (printContent) {
                printToIframe(data.orderNumber, printContent.innerHTML);
                toast.success(`Impression : #${data.orderNumber}`);
            }
        }, 500);
    };

    useEffect(() => {
        if (printData) {
            handlePrint(printData);
            setPrintData(null);
        }
    }, [printData]);

    const loadOrders = async (silent = false) => {
        if (!silent) setIsLoading(true);
        try {
            const res: any = await getTodayOrders({});
            if (res && res.success === false) {
                toast.error("Erreur de s├®curit├® : " + res.error);
                setAllTodayOrders([]);
            } else {
                setAllTodayOrders(Array.isArray(res) ? res : []);
                setLastReloadTime(new Date());
            }
        } catch (error) {
            console.error("Orders load failed:", error);
            setAllTodayOrders([]);
        } finally {
            if (!silent) setIsLoading(false);
        }
    };

    useEffect(() => {
        loadOrders();
        const loadClients = async () => {
            const res: any = await getAllClients({});
            setAllClients(Array.isArray(res) ? res : []);
        };
        loadClients();

        // POLL Strategy: 10s (Extended from 3s)
        const interval = setInterval(async () => {
            await loadOrders(true);
        }, 10000);

        return () => clearInterval(interval);
    }, []);

    useEffect(() => {
        if (currentOrder) {
            setRemise(0);
            setMontantRecu(Number(currentOrder.totalAmount));
            setSelectedClientId(null);

            // AUTO-SELECT BEST MARGIN SUPPLIER
            const initialSuppliers: Record<number, number> = {};
            (currentOrder.items as any[]).forEach(item => {
                if (item.variant?.variantSuppliers?.length > 0) {
                    // Sort by cost (simplified: assumes same currency for current cheapest logic if both USD or both DZD)
                    const cheapest = [...item.variant.variantSuppliers].sort((a, b) =>
                        parseFloat(a.purchasePrice) - parseFloat(b.purchasePrice)
                    )[0];
                    initialSuppliers[item.id] = cheapest.supplierId;
                }
            });
            setItemSuppliers(initialSuppliers);
        }
    }, [currentOrder]);

    const handleEncaisser = async (clientIdOverride?: number) => {
        if (!currentOrder || !user) return;

        const totalApresRemise = Number(currentOrder.totalAmount) - remise;
        const effectiveRecu = montantRecu === "" ? totalApresRemise : Number(montantRecu);
        const finalClientId = clientIdOverride || selectedClientId;

        if (effectiveRecu < totalApresRemise && !finalClientId) {
            setIsCreatingClient(true);
            return;
        }

        setIsUpdating(true);
        try {
            const res: any = await payOrder({
                id: currentOrder.id,
                options: {
                    remise,
                    montantPaye: effectiveRecu,
                    clientId: finalClientId || undefined,
                    itemSuppliers
                }
            });
            if (res.success && res.order) {
                toast.success(`Commande #${currentOrder.orderNumber} encaiss├®e avec succ├¿s !`, {
                    style: { background: '#052e16', color: '#4ade80', border: '1px solid #14532d' }
                });

                // Prepare and trigger Print ONLY if delivery method is TICKET
                if (res.order.deliveryMethod === "TICKET") {
                    const hasManual = res.order.items?.some((it: any) => it.variant?.product?.isManualDelivery);

                    // If it has manual delivery, we might want to skip automatic printing of codes 
                    // since they aren't generated yet. For now, we skip if the user specifically asked for "normal" manual flow.
                    if (!hasManual) {
                        setPrintData({
                            orderNumber: res.order.orderNumber,
                            date: res.order.createdAt,
                            items: (res.order.items || []).map((it: any) => ({
                                name: it.name,
                                quantity: it.quantity,
                                price: it.price,
                                codes: it.codes,
                                customData: it.customData,
                                playerNickname: it.playerNickname
                            })),
                            totalAmount: res.order.totalAmount,
                            paymentMethod: effectiveRecu >= (Number(res.order.totalAmount) - Number(res.order.remise)) ? "Esp├¿ces" : "Cr├®dit / Partiel"
                        });
                    } else {
                        toast.success("Commande ├á livraison manuelle (Impression diff├®r├®e)");
                    }
                }

                setCurrentOrder(null);
                loadOrders();
            } else {
                toast.error("├ëchec de l'encaissement: " + res.error);
            }
        } catch (error) {
            console.error("Update failed:", error);
            toast.error("Erreur technique lors de l'encaissement");
        } finally {
            setIsUpdating(false);
            if (clientIdOverride) setIsCreatingClient(false);
        }
    };


    const statusMap: Record<string, string> = {
        "Toutes": "ALL",
        "En attente": "EN_ATTENTE",
        "Pay├®es": "PAYE",
        "Livr├®es": "TERMINE",
        "Partiel": "PARTIEL",
        "Dettes": "NON_PAYE",
        "Rembours├®s": "REMBOURSE"
    };

    const handleCancelOrder = async (orderId: number) => {
        if (!confirm("├ètes-vous s├╗r de vouloir annuler/rembourser cette commande ? Cette action est irr├®versible et lib├®rera les codes digitaux associ├®s.")) return;

        setIsUpdating(true);
        try {
            const res = await cancelOrderAction({ orderId });
            if (res.success) {
                toast.success("Commande annul├®e avec succ├¿s");
                setIsDetailModalOpen(false);
                loadOrders();
            } else {
                toast.error("Erreur: " + res.error);
            }
        } catch (error) {
            console.error("Cancel failed:", error);
            toast.error("Erreur technique lors de l'annulation");
        } finally {
            setIsUpdating(false);
        }
    };

    const getStatusConfig = (status: string) => {
        switch (status) {
            case "EN_ATTENTE":
                return { label: "├Ç Encaisser", classes: "bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400 border-amber-200 dark:border-amber-800" };
            case "PAYE":
                return { label: "Pay├®", classes: "bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800" };
            case "TERMINE":
                return { label: "Livr├®e", classes: "bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400 border-blue-200 dark:border-blue-800" };
            case "PARTIEL":
                return { label: "Partiel", classes: "bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400 border-orange-200 dark:border-orange-800" };
            case "NON_PAYE":
                return { label: "Dette", classes: "bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400 border-red-200 dark:border-red-800" };
            case "REMBOURSE":
                return { label: "Rembours├®", classes: "bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400 border-purple-200 dark:border-purple-800" };
            default:
                return { label: status, classes: "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400 border-slate-200 dark:border-slate-700" };
        }
    };

    const filteredOrders = allTodayOrders.filter(o => {
        const matchesSearch = o.orderNumber.toLowerCase().includes(searchQuery.toLowerCase());
        if (!matchesSearch) return false;
        if (filterStatus === "Toutes") return true;
        return o.status === statusMap[filterStatus];
    });

    return (
        <main className="flex flex-1 min-w-0 overflow-hidden h-[calc(100vh-64px)] mx-[-32px] my-[-32px] bg-background-light dark:bg-background-dark font-sans antialiased">
            <style jsx global>{`
                .custom-scrollbar::-webkit-scrollbar { width: 4px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(236, 91, 19, 0.2); border-radius: 10px; }
            `}</style>

            {/* Left Zone (60%) - Order List */}
            <section className="flex-[0.6] min-w-0 flex flex-col bg-background-light dark:bg-[#221610] border-r border-[#ec5b13]/10">
                {/* Header / Filters */}
                <header className="p-6 space-y-6">
                    <div className="flex items-center justify-between gap-4">
                        <div className="flex items-center gap-3">
                            <h2 className="text-lg font-bold tracking-tight shrink-0 text-[#ec5b13]">Commandes du jour</h2>
                            <div className="hidden sm:flex items-center gap-2 px-2 py-1 bg-slate-100 dark:bg-white/5 rounded-lg border border-slate-200 dark:border-white/10">
                                <span className={`w-1.5 h-1.5 rounded-full ${isLoading ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500'}`}></span>
                                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-tighter">
                                    Actualis├® ├á {lastReloadTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                                </span>
                                <button
                                    onClick={() => loadOrders()}
                                    disabled={isLoading}
                                    className="ml-1 p-0.5 hover:text-[#ec5b13] transition-colors disabled:opacity-30"
                                >
                                    <span className={`material-symbols-outlined !text-[14px] ${isLoading ? 'animate-spin' : ''}`}>refresh</span>
                                </button>
                            </div>
                        </div>
                        <div className="flex flex-nowrap gap-1 p-1 bg-slate-200 dark:bg-[#ec5b13]/5 rounded-xl transition-all overflow-x-auto scrollbar-hide">
                            {["Toutes", "En attente", "Pay├®es", "Partiel", "Dettes", "Livr├®es", "Rembours├®s"].map((s) => (
                                <button
                                    key={s}
                                    onClick={() => setFilterStatus(s)}
                                    className={`px-2 py-1 text-[10px] font-black uppercase tracking-tighter rounded-lg transition-all whitespace-nowrap ${filterStatus === s
                                        ? "bg-white dark:bg-[#ec5b13] text-[#ec5b13] dark:text-white shadow-sm"
                                        : "text-slate-500 hover:text-[#ec5b13]"
                                        }`}
                                >
                                    {s}
                                </button>
                            ))}
                        </div>

                        {/* WebUSB Hardware UI */}
                        <div className="flex items-center gap-2 pl-4 border-l border-[#ec5b13]/20">
                            <div className={`hidden lg:flex items-center gap-1.5 px-2 py-1 rounded-md border text-[9px] font-bold uppercase tracking-tight transition-all ${webusb.connected
                                ? "bg-emerald-500/10 border-emerald-500/20 text-emerald-400"
                                : "bg-red-500/10 border-red-500/20 text-red-400"
                                }`}>
                                <div className={`size-1.5 rounded-full ${webusb.connected ? "bg-emerald-400 animate-pulse" : "bg-red-400"}`} />
                                {webusb.connected ? "USB Pr├¬te" : "Hors ligne"}
                            </div>
                            <button
                                onClick={webusb.connected ? webusb.disconnect : webusb.connect}
                                disabled={webusb.isConnecting}
                                className={`h-8 px-3 rounded-lg flex items-center gap-2 text-[10px] font-black uppercase transition-all shadow-sm active:scale-95 ${webusb.connected
                                    ? "bg-zinc-800 text-zinc-400 hover:bg-zinc-700"
                                    : "bg-[#ec5b13] text-white hover:bg-orange-600"
                                    }`}
                            >
                                {webusb.isConnecting ? <Loader2 className="size-3 animate-spin" /> : <Usb className="size-3" />}
                                {webusb.connected ? "Off" : "USB"}
                            </button>
                        </div>
                    </div>
                    <div className="relative">
                        <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">search</span>
                        <input
                            className="w-full bg-white dark:bg-[#ec5b13]/5 border border-slate-200 dark:border-[#ec5b13]/20 rounded-xl py-3 pl-12 pr-4 focus:ring-2 focus:ring-[#ec5b13] focus:border-transparent outline-none transition-all placeholder:text-slate-400"
                            placeholder="Rechercher une commande (ex: #A45)"
                            type="text"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                </header>

                {/* Orders List / Cards */}
                <div className="flex-1 overflow-y-auto custom-scrollbar px-6 pb-6">
                    {/* Desktop Table View */}
                    <div className="hidden md:block bg-white dark:bg-[#ec5b13]/5 rounded-2xl border border-slate-200 dark:border-[#ec5b13]/10 overflow-x-auto shadow-sm">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="border-b border-slate-100 dark:border-[#ec5b13]/10 bg-slate-50 dark:bg-[#ec5b13]/10">
                                    <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-slate-500">Order #</th>
                                    <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-slate-500">Heure</th>
                                    <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-slate-500">Montant</th>
                                    <th className="px-6 py-4 text-xs font-bold uppercase tracking-wider text-slate-500 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-[#ec5b13]/10">
                                {isLoading && allTodayOrders.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="p-12 text-center"><Spinner color="warning" /></td>
                                    </tr>
                                ) : filteredOrders.map((o) => {
                                    const config = getStatusConfig(o.status);
                                    const isActive = currentOrder?.id === o.id;
                                    return (
                                        <tr
                                            key={o.id}
                                            onClick={() => setCurrentOrder(o)}
                                            className={`cursor-pointer transition-colors ${isActive ? 'bg-[#ec5b13]/5 border-l-4 border-l-[#ec5b13]' : 'hover:bg-slate-50 dark:hover:bg-[#ec5b13]/10 border-l-4 border-l-transparent'}`}
                                        >
                                            <td className={`px-6 py-4 font-bold ${isActive ? 'text-[#ec5b13]' : ''}`}>
                                                <div className="flex items-center gap-2">
                                                    <span>{o.orderNumber.startsWith('#') ? o.orderNumber : `#${o.orderNumber}`}</span>
                                                    {o.deliveryMethod === "WHATSAPP" && (
                                                        <Tooltip content={`WhatsApp: +213 ${o.customerPhone}`} color="success">
                                                            <div className="bg-[#25D366]/10 p-1 rounded-md">
                                                                <svg className="w-4 h-4 text-[#25D366]" fill="currentColor" viewBox="0 0 24 24">
                                                                    <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.438 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"></path>
                                                                </svg>
                                                            </div>
                                                        </Tooltip>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-sm text-slate-500 dark:text-slate-400">
                                                {new Date(o.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </td>
                                            <td className="px-6 py-4 font-semibold whitespace-nowrap">{formatCurrency(o.totalAmount, 'DZD')}</td>
                                            <td className="px-6 py-4 text-right">
                                                <div className="flex items-center justify-end gap-3">
                                                    <span className={`inline-flex items-center px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border shrink-0 ${config.classes}`}>
                                                        {config.label}
                                                    </span>
                                                    <button
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            setOrderForDetail(o);
                                                            setIsDetailModalOpen(true);
                                                        }}
                                                        className="p-1.5 rounded-lg bg-white/5 hover:bg-[#ec5b13]/20 text-slate-400 hover:text-[#ec5b13] transition-all"
                                                    >
                                                        <Eye size={14} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>

                    {/* Mobile Card View */}
                    <div className="md:hidden space-y-4">
                        {isLoading && allTodayOrders.length === 0 ? (
                            <div className="flex justify-center p-12"><Spinner color="warning" /></div>
                        ) : filteredOrders.map((o) => {
                            const config = getStatusConfig(o.status);
                            const isActive = currentOrder?.id === o.id;
                            return (
                                <div
                                    key={o.id}
                                    onClick={() => setCurrentOrder(o)}
                                    className={`p-4 rounded-2xl border transition-all cursor-pointer ${isActive
                                        ? 'bg-[#ec5b13]/10 border-[#ec5b13] shadow-lg shadow-[#ec5b13]/5 ring-1 ring-[#ec5b13]/20'
                                        : 'bg-white dark:bg-[#ec5b13]/5 border-slate-200 dark:border-[#ec5b13]/10 shadow-sm'
                                        }`}
                                >
                                    <div className="flex items-center justify-between mb-3">
                                        <div className="flex items-center gap-2">
                                            <span className={`text-sm font-black ${isActive ? 'text-[#ec5b13]' : 'text-slate-900 dark:text-white'}`}>
                                                {o.orderNumber.startsWith('#') ? o.orderNumber : `#${o.orderNumber}`}
                                            </span>
                                            {o.deliveryMethod === "WHATSAPP" && (
                                                <div className="bg-[#25D366]/10 p-1 rounded-md">
                                                    <svg className="w-3 h-3 text-[#25D366]" fill="currentColor" viewBox="0 0 24 24">
                                                        <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.438 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"></path>
                                                    </svg>
                                                </div>
                                            )}
                                        </div>
                                        <span className="text-[10px] text-slate-400 font-bold uppercase">
                                            {new Date(o.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                        </span>
                                    </div>
                                    <div className="flex items-end justify-between">
                                        <div>
                                            <p className="text-xs text-slate-500 font-medium mb-1">Total ├á r├®gler</p>
                                            <p className="text-lg font-black text-slate-900 dark:text-white">{formatCurrency(o.totalAmount, 'DZD')}</p>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <span className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-tighter border ${config.classes}`}>
                                                {config.label}
                                            </span>
                                            <Button
                                                isIconOnly
                                                size="sm"
                                                variant="light"
                                                onPress={(e) => {
                                                    setOrderForDetail(o);
                                                    setIsDetailModalOpen(true);
                                                }}
                                                className="text-[#ec5b13]"
                                            >
                                                <Eye size={16} />
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </section>

            {/* Right Zone (40%) - Checkout Panel */}
            <section className="flex-[0.4] flex flex-col bg-white dark:bg-[#110b08]/80 backdrop-blur-md">
                {currentOrder ? (
                    <div className="flex-1 flex flex-col p-6 overflow-hidden">
                        {/* Checkout Header */}
                        <div className="flex items-center justify-between mb-8 shrink-0">
                            <div>
                                <div className="flex items-center gap-3">
                                    <h3 className="text-xl font-bold">Commande {currentOrder.orderNumber.startsWith('#') ? currentOrder.orderNumber : `#${currentOrder.orderNumber}`}</h3>
                                    {currentOrder.deliveryMethod === "WHATSAPP" && (
                                        <div className="flex items-center gap-1.5 px-2.5 py-1 bg-[#25D366]/10 text-[#25D366] rounded-lg border border-[#25D366]/20">
                                            <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24">
                                                <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.438 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413Z"></path>
                                            </svg>
                                            <span className="text-[10px] font-black uppercase">WhatsApp</span>
                                        </div>
                                    )}
                                </div>
                                <div className="flex items-center gap-2 mt-1">
                                    <span className={`w-2 h-2 rounded-full animate-pulse ${currentOrder.status === 'EN_ATTENTE' ? 'bg-amber-500' : 'bg-emerald-500'}`}></span>
                                    <span className="text-xs text-slate-500 font-medium">
                                        {currentOrder.deliveryMethod === "WHATSAPP" ? `WhatsApp: +213 ${currentOrder.customerPhone}` : "Ticket Imprim├® (Standard)"}
                                    </span>
                                </div>
                            </div>
                            <span className={`px-4 py-1.5 rounded-xl text-xs font-bold uppercase border shrink-0 ${getStatusConfig(currentOrder.status).classes}`}>
                                {getStatusConfig(currentOrder.status).label}
                            </span>
                        </div>

                        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 pr-2 mb-6">
                            {(currentOrder.items as any[]).map((item, idx) => {
                                const linkedSuppliers = item.variant?.variantSuppliers || [];
                                return (
                                    <div key={idx} className="flex flex-col gap-3 p-4 rounded-2xl bg-slate-50 dark:bg-[#ec5b13]/5 border border-slate-200 dark:border-[#ec5b13]/10 group">
                                        <div className="flex items-center gap-4">
                                            <div className="w-12 h-12 rounded-xl bg-[#ec5b13]/20 flex items-center justify-center overflow-hidden shrink-0">
                                                <span className="material-symbols-outlined text-[#ec5b13] text-xl">category</span>
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <p className="font-bold text-sm truncate uppercase tracking-tight">{item.name}</p>
                                                {item.customData && (
                                                    <p className="text-[10px] text-[#ec5b13] font-black uppercase tracking-widest mt-0.5 flex items-center gap-1">
                                                        <span className="material-symbols-outlined !text-[12px]">poker_chip</span>
                                                        ID/LIEN: {item.customData}
                                                    </p>
                                                )}
                                                {item.playerNickname && (
                                                    <p className="text-[10px] text-emerald-500 font-black uppercase tracking-widest mt-0.5 flex items-center gap-1">
                                                        <span className="material-symbols-outlined !text-[12px]">person</span>
                                                        PSEUDO: {item.playerNickname}
                                                    </p>
                                                )}
                                                <p className="text-[10px] text-slate-500 font-bold">Qty: {item.quantity} ÔÇó {formatCurrency(item.price, 'DZD')}</p>
                                            </div>
                                            <div className="text-right shrink-0">
                                                <p className="font-black text-white">{formatCurrency(Number(item.price) * item.quantity, 'DZD')}</p>
                                            </div>
                                        </div>

                                        {/* Supplier Selector */}
                                        {linkedSuppliers.length > 0 && (
                                            <div className="flex items-center gap-2 pt-2 border-t border-[#ec5b13]/10">
                                                <span className="text-[10px] font-bold text-slate-500 uppercase shrink-0">Acheter via:</span>
                                                <select
                                                    className="flex-1 bg-black/40 border border-[#ec5b13]/20 rounded-lg px-2 py-1 text-[11px] text-white outline-none cursor-pointer hover:border-[#ec5b13]/50 transition-colors"
                                                    value={itemSuppliers[item.id] || ""}
                                                    onChange={(e) => setItemSuppliers(prev => ({ ...prev, [item.id]: parseInt(e.target.value) }))}
                                                >
                                                    {linkedSuppliers.map((ls: any) => (
                                                        <option key={ls.supplier.id} value={ls.supplier.id} className="bg-[#1a1614]">
                                                            {ls.supplier.name} ({formatCurrency(ls.purchasePrice, ls.currency)})
                                                        </option>
                                                    ))}
                                                </select>
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>

                        {/* Financial Block */}
                        <div className="border-t border-slate-200 dark:border-[#ec5b13]/20 pt-6 space-y-4 shrink-0">
                            <div className="flex justify-between items-center text-sm font-medium">
                                <span className="text-slate-500">Sous-total</span>
                                <span className="whitespace-nowrap">{formatCurrency(currentOrder.totalAmount, 'DZD')}</span>
                            </div>

                            {/* Remise & Client Block */}
                            <div className="grid grid-cols-2 gap-3">
                                <div className="flex flex-col gap-1.5 p-3 bg-slate-50 dark:bg-white/5 rounded-xl border border-slate-200 dark:border-white/10">
                                    <span className="text-[10px] uppercase font-bold text-slate-500">Remise (DZD)</span>
                                    <input
                                        className="bg-transparent border-none focus:ring-0 p-0 font-bold text-emerald-500 outline-none w-full"
                                        type="number"
                                        placeholder="0"
                                        value={remise}
                                        onChange={(e) => setRemise(Number(e.target.value))}
                                    />
                                </div>
                                <div className="flex flex-col gap-1.5 p-3 bg-slate-50 dark:bg-white/5 rounded-xl border border-slate-200 dark:border-white/10">
                                    <span className="text-[10px] uppercase font-bold text-slate-500">Montant Re├ºu</span>
                                    <input
                                        className="bg-transparent border-none focus:ring-0 p-0 font-bold text-[#ec5b13] outline-none w-full"
                                        type="number"
                                        placeholder="0"
                                        value={montantRecu}
                                        onChange={(e) => setMontantRecu(e.target.value)}
                                    />
                                </div>
                            </div>

                            {/* Quick Modes */}
                            <div className="flex gap-2">
                                <Button
                                    size="sm"
                                    variant="flat"
                                    className="flex-1 bg-emerald-500/10 text-emerald-500 font-bold text-[10px] uppercase h-8"
                                    onPress={() => setMontantRecu(Number(currentOrder.totalAmount) - remise)}
                                >
                                    Paiement Total
                                </Button>
                                <Button
                                    size="sm"
                                    variant="flat"
                                    className="flex-1 bg-red-500/10 text-red-500 font-bold text-[10px] uppercase h-8"
                                    onPress={() => setMontantRecu(0)}
                                >
                                    Cr├®dit (0 DZD)
                                </Button>
                            </div>

                            {/* Client Selection */}
                            <div className="p-3 bg-slate-50 dark:bg-white/5 rounded-xl border border-slate-200 dark:border-white/10 space-y-2">
                                <div className="flex justify-between items-center">
                                    <span className="text-[10px] uppercase font-bold text-slate-500 flex items-center gap-1">
                                        <UserIcon size={10} /> Client (Optionnel)
                                    </span>
                                    {selectedClientId && (
                                        <button onClick={() => setSelectedClientId(null)} className="text-[10px] text-red-500 font-bold uppercase">X Annuler</button>
                                    )}
                                </div>
                                <div className="flex gap-2">
                                    <select
                                        className="bg-transparent border-none focus:ring-0 p-0 text-sm font-semibold text-white flex-1 outline-none"
                                        value={selectedClientId || ""}
                                        onChange={(e) => setSelectedClientId(Number(e.target.value) || null)}
                                    >
                                        <option value="" className="bg-[#1a1614]">Client de passage</option>
                                        {allClients.map(c => (
                                            <option key={c.id} value={c.id} className="bg-[#1a1614]">{c.nomComplet}</option>
                                        ))}
                                    </select>
                                    <button
                                        onClick={() => setIsCreatingClient(true)}
                                        className="p-1 rounded bg-[#ec5b13]/20 text-[#ec5b13] hover:bg-[#ec5b13]/30 transition-colors"
                                    >
                                        <Plus size={14} />
                                    </button>
                                </div>
                            </div>

                            <div className="flex justify-between items-end pt-2">
                                <span className="text-sm font-bold uppercase tracking-widest text-slate-500 pb-2">Reste ├á payer</span>
                                <div className="text-right">
                                    <span className={`text-4xl font-black tracking-tight whitespace-nowrap ${(Number(currentOrder.totalAmount) - remise - (montantRecu === "" ? (Number(currentOrder.totalAmount) - remise) : Number(montantRecu))) > 0 ? 'text-red-500' : 'text-[#ec5b13]'}`}>
                                        {formatCurrency(Math.max(0, Number(currentOrder.totalAmount) - remise - (montantRecu === "" ? (Number(currentOrder.totalAmount) - remise) : Number(montantRecu))), 'DZD')}
                                    </span>
                                    <span className="text-xl font-bold ml-1 opacity-50">DZD</span>
                                </div>
                            </div>
                        </div>

                        {/* Payment Actions */}
                        {currentOrder.status === 'EN_ATTENTE' && (
                            <div className="grid gap-4 mt-8 shrink-0 pb-2 grid-cols-1">
                                <button
                                    onClick={() => handleEncaisser()}
                                    disabled={isUpdating}
                                    className="flex flex-col items-center justify-center gap-2 p-5 rounded-2xl bg-gradient-to-br from-emerald-500 to-emerald-700 text-white shadow-lg shadow-emerald-500/20 hover:scale-[1.02] active:scale-100 transition-transform disabled:opacity-50"
                                >
                                    {isUpdating ? <Spinner size="sm" color="white" /> : (
                                        <>
                                            <span className="material-symbols-outlined text-3xl">payments</span>
                                            <span className="text-xs font-bold uppercase tracking-tighter">Encaisser Esp├¿ces</span>
                                        </>
                                    )}
                                </button>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-slate-400">
                        <span className="material-symbols-outlined text-6xl mb-4 opacity-20">receipt_long</span>
                        <p className="font-semibold">S├®lectionnez une commande pour voir les d├®tails</p>
                    </div>
                )}
            </section>

            <OrderDetailModal
                isOpen={isDetailModalOpen}
                onClose={() => setIsDetailModalOpen(false)}
                order={orderForDetail}
                onRefund={async (id) => {
                    const res = await refundFullOrder({ id, returnToStock: false });
                    if (res.success) {
                        setIsDetailModalOpen(false);
                        loadOrders();
                    }
                }}
                onReplaceCode={async (orderItemId, codeId, type, reason) => {
                    const res = await replaceOrderItemCode({
                        orderItemId,
                        oldCodeId: type === 'standard' ? codeId : undefined,
                        oldSlotId: type === 'slot' ? codeId : undefined,
                        reason
                    });
                    if (res.success) loadOrders();
                }}
                onRefundItem={async (orderItemId, returnToStock) => {
                    const res = await refundOrderItem({ orderItemId, returnToStock });
                    if (res.success) loadOrders();
                }}
                onReprint={async () => {
                    if (!orderForDetail) return;
                    const enrichedItems = orderForDetail.items.map((it: any) => {
                        const standard = (it.fullCodes || []).map((c: any) => c.code);
                        const slots = (it.fullSlots || []).map((s: any) => `${s.parentCode} | Profil ${s.slotNumber}`);
                        return {
                            name: it.name,
                            quantity: it.quantity,
                            price: it.price,
                            codes: [...standard, ...slots],
                            customData: it.customData,
                            playerNickname: it.playerNickname
                        };
                    });

                    const dataToPrint = {
                        orderNumber: orderForDetail.orderNumber,
                        date: orderForDetail.createdAt,
                        items: enrichedItems,
                        totalAmount: orderForDetail.totalAmount,
                        paymentMethod: orderForDetail.paymentMethod || "Esp├¿ces",
                        cashier: user?.nom || "Admin"
                    };

                    if (webusb.connected) {
                        try {
                            const buffer = generateOrderEscPos(dataToPrint, settings);
                            await webusb.print(buffer);
                            toast.success("R├®impression USB lanc├®e");
                        } catch (e) {
                            console.error("Manual reprint fail:", e);
                            toast.error("Erreur USB");
                        }
                    } else {
                        const printContent = document.getElementById('thermal-receipt-source');
                        if (printContent) {
                            toast.loading("Lancement r├®impression...", { duration: 2000 });
                            printToIframe(orderForDetail.orderNumber, printContent.innerHTML);
                        }
                    }
                }}
            />

            {/* Auto New Client Modal */}
            <Modal
                isOpen={isCreatingClient}
                onClose={() => setIsCreatingClient(false)}
                classNames={{ base: "bg-[#161616] text-white border border-[#262626]" }}
            >
                <ModalContent>
                    {(onClose) => {
                        const innerSave = async () => {
                            if (!newClientName) return;
                            try {
                                const res: any = await createClient({ nom: newClientName, telephone: newClientPhone });
                                if (res.success && res.client) {
                                    const newC = res.client;
                                    // Refresh list
                                    const clientsRes: any = await getAllClients({});
                                    setAllClients(Array.isArray(clientsRes) ? clientsRes : []);
                                    setSelectedClientId(newC.id);

                                    // AUTO VALIDATE TRANSACTION
                                    await handleEncaisser(newC.id);

                                    setIsCreatingClient(false);
                                    setNewClientName("");
                                    setNewClientPhone("");
                                } else {
                                    toast.error(res.error || "Erreur cr├®ation client");
                                }
                            } catch (e) { toast.error("Erreur cr├®ation client"); }

                        };

                        return (
                            <>
                                <ModalHeader className="flex flex-col gap-1">
                                    <h3 className="text-xl font-bold">Nouveau Profil Client</h3>
                                    <p className="text-xs text-slate-400">Requis pour enregistrer un cr├®dit</p>
                                </ModalHeader>
                                <ModalBody className="gap-4">
                                    <div className="space-y-4">
                                        <div className="flex flex-col gap-2">
                                            <span className="text-[10px] uppercase font-bold text-slate-500">Nom Complet</span>
                                            <input
                                                autoFocus
                                                className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl p-3 text-sm focus:border-[#ec5b13] outline-none transition-colors"
                                                placeholder="Ex: Ahmed Ben"
                                                value={newClientName}
                                                onChange={(e) => setNewClientName(e.target.value)}
                                            />
                                        </div>
                                        <div className="flex flex-col gap-2">
                                            <span className="text-[10px] uppercase font-bold text-slate-500">T├®l├®phone (Optionnel)</span>
                                            <input
                                                className="w-full bg-[#0a0a0a] border border-[#262626] rounded-xl p-3 text-sm focus:border-[#ec5b13] outline-none transition-colors"
                                                placeholder="0X XX XX XX XX"
                                                value={newClientPhone}
                                                onChange={(e) => setNewClientPhone(e.target.value)}
                                            />
                                        </div>
                                    </div>
                                </ModalBody>
                                <ModalFooter>
                                    <Button variant="flat" onPress={onClose} className="text-slate-400">Ignorer</Button>
                                    <Button
                                        className="bg-[#ec5b13] text-white font-bold px-8"
                                        onPress={innerSave}
                                    >
                                        Valider & S├®lectionner
                                    </Button>
                                </ModalFooter>
                            </>
                        );
                    }}
                </ModalContent>
            </Modal>

            {/* Hidden Print Container - Sync source for hook */}
            <div
                id="thermal-receipt-source"
                className="fixed -top-[9999px] -left-[9999px] opacity-0 pointer-events-none text-black bg-white"
                aria-hidden="true"
            >
                {printData && <ThermalReceiptV2 {...printData} />}
            </div>
        </main>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Spinner, Button, Modal, ModalContent, ModalHeader, ModalBody, ModalFooter } from "@heroui/react";
import { useOrderStore } from "@/store/useOrderStore";
import { useAuthStore } from "@/store/useAuthStore";
import { toast } from "react-hot-toast";
import { Eye, Search, Filter, ArrowLeft, RefreshCw, Smartphone, User as UserIcon, Plus, Usb, Loader2 } from "lucide-react";
import { formatCurrency } from "@/lib/formatters";
import { useThermalPrinter } from "@/hooks/useThermalPrinter";
import { useWebUSBPrinter } from "@/hooks/useWebUSBPrinter";
import { generateOrderEscPos } from "@/lib/escpos";
import { useSettingsStore } from "@/store/useSettingsStore";
import { ThermalReceiptV2 } from "@/components/admin/receipt/ThermalReceiptV2";
import OrderDetailModal from "@/components/admin/modals/OrderDetailModal";
import { getAllClients, createClient } from "../clients/actions";
import { refundFullOrder, replaceOrderItemCode, refundOrderItem, payOrder, getTodayOrders, cancelOrderAction } from "./actions";

export default function CaisseMobile() {
    const {
        currentOrder,
        setCurrentOrder,
        searchQuery,
        setSearchQuery,
    } = useOrderStore();
    const { user } = useAuthStore();

    const [isUpdating, setIsUpdating] = useState(false);
    const [allTodayOrders, setAllTodayOrders] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState<string>("Tous");
    const [remise, setRemise] = useState<number>(0);
    const [montantRecu, setMontantRecu] = useState<number | string>("");
    const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
    const [orderForDetail, setOrderForDetail] = useState<any | null>(null);
    const [isCreatingClient, setIsCreatingClient] = useState(false);
    const [newClientName, setNewClientName] = useState("");
    const [newClientPhone, setNewClientPhone] = useState("");
    const [allClients, setAllClients] = useState<any[]>([]);
    const [selectedClientId, setSelectedClientId] = useState<number | null>(null);
    const [itemSuppliers, setItemSuppliers] = useState<Record<number, number>>({});
    const [printData, setPrintData] = useState<any>(null);
    const [lastReloadTime, setLastReloadTime] = useState<Date>(new Date());
    const { printToIframe } = useThermalPrinter();

    const settings = useSettingsStore();
    const webusb = useWebUSBPrinter();

    const handlePrint = async (data: any) => {
        // Strategy 1: High-Performance WebUSB
        if (webusb.connected) {
            try {
                const buffer = generateOrderEscPos(data, settings);
                await webusb.print(buffer);
                toast.success(`Ticket USB : #${data.orderNumber}`, { icon: 'ÔÜí' });
                return;
            } catch (error) {
                console.error("Mobile Caisse USB Print fail:", error);
                toast.error("├ëchec USB, basculement mode standard...");
            }
        }

        // Strategy 2: Standard Iframe Fallback
        setTimeout(() => {
            const printContent = document.getElementById('thermal-receipt-source');
            if (printContent) {
                printToIframe(data.orderNumber, printContent.innerHTML);
                toast.success(`Impression : #${data.orderNumber}`);
            }
        }, 500);
    };

    useEffect(() => {
        if (printData) {
            handlePrint(printData);
            setPrintData(null);
        }
    }, [printData]);

    const loadOrders = async (silent = false) => {
        if (!silent) setIsLoading(true);
        try {
            const res: any = await getTodayOrders({});
            if (res && res.success !== false) {
                setAllTodayOrders(Array.isArray(res) ? res : []);
                setLastReloadTime(new Date());
            }
        } catch (error) {
            console.error("Orders load failed:", error);
        } finally {
            if (!silent) setIsLoading(false);
        }
    };

    useEffect(() => {
        loadOrders();
        const loadClients = async () => {
            const res: any = await getAllClients({});
            setAllClients(Array.isArray(res) ? res : []);
        };
        loadClients();
        const interval = setInterval(() => loadOrders(true), 10000);
        return () => clearInterval(interval);
    }, []);

    useEffect(() => {
        if (currentOrder) {
            setRemise(0);
            setMontantRecu(Number(currentOrder.totalAmount));
            setSelectedClientId(null);
            const initialSuppliers: Record<number, number> = {};
            (currentOrder.items as any[]).forEach(item => {
                if (item.variant?.variantSuppliers?.length > 0) {
                    const cheapest = [...item.variant.variantSuppliers].sort((a, b) =>
                        parseFloat(a.purchasePrice) - parseFloat(b.purchasePrice)
                    )[0];
                    initialSuppliers[item.id] = cheapest.supplierId;
                }
            });
            setItemSuppliers(initialSuppliers);
        }
    }, [currentOrder]);

    const handleEncaisser = async (clientIdOverride?: number) => {
        if (!currentOrder || !user) return;

        const totalApresRemise = Number(currentOrder.totalAmount) - remise;
        const effectiveRecu = montantRecu === "" ? totalApresRemise : Number(montantRecu);
        const finalClientId = clientIdOverride || selectedClientId;

        if (effectiveRecu < totalApresRemise && !finalClientId) {
            setIsCreatingClient(true);
            return;
        }

        setIsUpdating(true);
        try {
            const res: any = await payOrder({
                id: currentOrder.id,
                options: {
                    remise,
                    montantPaye: effectiveRecu,
                    clientId: finalClientId || undefined,
                    itemSuppliers
                }
            });
            if (res.success && res.order) {
                toast.success(`Encaiss├® ! #${currentOrder.orderNumber}`);

                if (res.order.deliveryMethod === "TICKET") {
                    const hasManual = res.order.items?.some((it: any) => it.variant?.product?.isManualDelivery);
                    if (!hasManual) {
                        setPrintData({
                            orderNumber: res.order.orderNumber,
                            date: res.order.createdAt,
                            items: (res.order.items || []).map((it: any) => ({
                                name: it.name,
                                quantity: it.quantity,
                                price: it.price,
                                codes: it.codes,
                                customData: it.customData,
                                playerNickname: it.playerNickname
                            })),
                            totalAmount: res.order.totalAmount,
                            paymentMethod: effectiveRecu >= (Number(res.order.totalAmount) - Number(res.order.remise)) ? "Esp├¿ces" : "Cr├®dit / Partiel"
                        });
                    }
                }

                setCurrentOrder(null);
                loadOrders();
            } else {
                toast.error(res.error);
            }
        } catch (e) {
            toast.error("Erreur technique");
        } finally {
            setIsUpdating(false);
            if (clientIdOverride) setIsCreatingClient(false);
        }
    };

    const orderStatusList = ["TOUT", "EN_ATTENTE", "PAYE", "NON_PAYE", "LIVRE", "TERMINE", "PARTIEL", "REMBOURSE"];
    const orderStatusDisplayMap: Record<string, string> = {
        TOUT: "Tous",
        EN_ATTENTE: "Attente",
        PAYE: "Pay├®es",
        NON_PAYE: "Dettes",
        LIVRE: "Livr├®es",
        TERMINE: "Finies",
        PARTIEL: "Partiel",
        REMBOURSE: "Rembours├®s"
    };

    const statusMap: Record<string, string> = {
        "Tous": "ALL",
        "Attente": "EN_ATTENTE",
        "Pay├®es": "PAYE",
        "Dettes": "NON_PAYE",
        "Livr├®es": "LIVRE",
        "Finies": "TERMINE",
        "Partiel": "PARTIEL",
        "Rembours├®s": "REMBOURSE"
    };

    const filteredOrders = allTodayOrders.filter(o => {
        const matchesSearch = o.orderNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
            o.id.toString().includes(searchQuery);
        if (!matchesSearch) return false;
        if (filterStatus === "Tous") return true;
        return o.status === statusMap[filterStatus];
    });

    const getStatusColor = (status: string) => {
        switch (status) {
            case "EN_ATTENTE": return "text-amber-500 bg-amber-500/10";
            case "PAYE": return "text-emerald-500 bg-emerald-500/10";
            case "LIVRE": return "text-blue-500 bg-blue-500/10";
            case "TERMINE": return "text-emerald-400 bg-emerald-400/10";
            case "NON_PAYE": return "text-red-500 bg-red-500/10";
            case "PARTIEL": return "text-purple-500 bg-purple-500/10";
            case "REMBOURSE": return "text-slate-400 bg-slate-400/10";
            default: return "text-slate-500 bg-slate-500/10";
        }
    };

    return (
        <div className="flex flex-col min-h-screen bg-[#0a0a0a] text-white">
            {/* Header */}
            <header className="p-4 border-b border-white/5 flex items-center justify-between sticky top-0 bg-[#0a0a0a]/80 backdrop-blur-md z-30">
                <div>
                    <h1 className="text-xl font-black tracking-tight text-[#ec5b13]">Caisse Mobile</h1>
                    <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{allTodayOrders.length} Commandes</p>
                </div>
                <div className="flex items-center gap-2">
                    {/* USB Status Indicator */}
                    <div className={`flex items-center gap-1 px-2 py-1 rounded bg-white/5 border text-[7px] font-black uppercase transition-all ${webusb.connected ? "border-emerald-500/30 text-emerald-400" : "border-white/10 text-slate-500"
                        }`}>
                        <div className={`size-1 rounded-full ${webusb.connected ? "bg-emerald-400 animate-pulse" : "bg-slate-600"}`} />
                        {webusb.connected ? "USB Pr├¬t" : "Standard"}
                    </div>

                    <button
                        onClick={webusb.connected ? webusb.disconnect : webusb.connect}
                        disabled={webusb.isConnecting}
                        className={`p-2 rounded-full transition-all active:scale-95 ${webusb.connected ? "bg-zinc-800 text-slate-400" : "bg-[#ec5b13]/10 text-[#ec5b13]"
                            }`}
                    >
                        {webusb.isConnecting ? <Loader2 size={18} className="animate-spin" /> : <Usb size={18} />}
                    </button>

                    <button onClick={() => loadOrders()} className="p-2 bg-white/5 rounded-full text-slate-400">
                        <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                    </button>
                </div>
            </header>

            {/* Content Switcher */}
            {currentOrder ? (
                /* Detail/Checkout View */
                <main className="flex-1 p-4 space-y-6 pb-32">
                    <button
                        onClick={() => setCurrentOrder(null)}
                        className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors"
                    >
                        <ArrowLeft size={20} />
                        <span className="font-bold text-sm">Retour ├á la liste</span>
                    </button>

                    <div className="bg-white/5 rounded-3xl p-6 border border-white/10">
                        <div className="flex justify-between items-start mb-6">
                            <div>
                                <h2 className="text-2xl font-black">#{currentOrder.orderNumber}</h2>
                                <p className="text-xs text-slate-500">{currentOrder.createdAt ? new Date(currentOrder.createdAt).toLocaleString() : ""}</p>
                            </div>
                            <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${getStatusColor(currentOrder.status)}`}>
                                {currentOrder.status}
                            </span>
                        </div>

                        <div className="space-y-4 mb-8">
                            {currentOrder.items?.map((item: any, idx: number) => {
                                const linkedSuppliers = item.variant?.variantSuppliers || [];
                                return (
                                    <div key={idx} className="p-3 bg-white/5 rounded-2xl border border-white/5 space-y-3">
                                        <div className="flex justify-between items-center text-sm">
                                            <span className="font-bold">{item.quantity}x {item.name}</span>
                                            <span className="font-black text-emerald-500">{formatCurrency(item.price * item.quantity, 'DZD')}</span>
                                        </div>
                                        {linkedSuppliers.length > 0 && (
                                            <div className="flex items-center gap-2 pt-2 border-t border-white/5">
                                                <span className="text-[9px] font-bold text-slate-500 uppercase">Via:</span>
                                                <select
                                                    className="flex-1 bg-black/40 border border-white/10 rounded-lg px-2 py-1 text-[10px] text-white outline-none"
                                                    value={itemSuppliers[item.id] || ""}
                                                    onChange={(e) => setItemSuppliers(prev => ({ ...prev, [item.id]: parseInt(e.target.value) }))}
                                                >
                                                    {linkedSuppliers.map((ls: any) => (
                                                        <option key={ls.supplier.id} value={ls.supplier.id}>
                                                            {ls.supplier.name} ({formatCurrency(ls.purchasePrice, ls.currency)})
                                                        </option>
                                                    ))}
                                                </select>
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>

                        <div className="space-y-4 pt-4 border-t border-white/10">
                            <div className="flex justify-between items-center">
                                <span className="text-slate-400">Total ├á payer</span>
                                <span className="text-2xl font-black text-[#ec5b13]">{formatCurrency(currentOrder.totalAmount, 'DZD')}</span>
                            </div>

                            {currentOrder.status === 'EN_ATTENTE' && (
                                <div className="space-y-4 pt-4">
                                    <div className="flex gap-2">
                                        <Button
                                            size="sm"
                                            className="flex-1 bg-emerald-500/10 text-emerald-500 font-black text-[10px] uppercase"
                                            onPress={() => setMontantRecu(Number(currentOrder.totalAmount) - remise)}
                                        >
                                            Total
                                        </Button>
                                        <Button
                                            size="sm"
                                            className="flex-1 bg-red-500/10 text-red-500 font-black text-[10px] uppercase"
                                            onPress={() => setMontantRecu(0)}
                                        >
                                            Dette
                                        </Button>
                                    </div>

                                    {/* Client Selector */}
                                    <div className="p-3 bg-white/5 rounded-2xl border border-white/10 space-y-2">
                                        <div className="flex justify-between items-center">
                                            <span className="text-[10px] uppercase font-bold text-slate-500 flex items-center gap-1">
                                                <UserIcon size={10} /> Client (Optionnel)
                                            </span>
                                            {selectedClientId && (
                                                <button onClick={() => setSelectedClientId(null)} className="text-[10px] text-red-500 font-bold uppercase">Annuler</button>
                                            )}
                                        </div>
                                        <div className="flex gap-2 text-white">
                                            <select
                                                className="bg-transparent border-none text-sm font-bold flex-1 outline-none appearance-none"
                                                value={selectedClientId || ""}
                                                onChange={(e) => setSelectedClientId(Number(e.target.value) || null)}
                                            >
                                                <option value="" className="bg-[#1a1614]">Client de passage</option>
                                                {allClients.map(c => (
                                                    <option key={c.id} value={c.id} className="bg-[#1a1614]">{c.nomComplet}</option>
                                                ))}
                                            </select>
                                            <button
                                                onClick={() => setIsCreatingClient(true)}
                                                className="p-1 rounded bg-[#ec5b13]/20 text-[#ec5b13]"
                                            >
                                                <Plus size={14} />
                                            </button>
                                        </div>
                                    </div>

                                    <button
                                        disabled={isUpdating}
                                        onClick={() => handleEncaisser()}
                                        className="w-full py-4 bg-gradient-to-r from-emerald-500 to-emerald-600 rounded-2xl font-black uppercase text-sm shadow-xl shadow-emerald-500/20 active:scale-95 transition-transform disabled:opacity-50"
                                    >
                                        {isUpdating ? <Spinner size="sm" color="white" /> : "Valider le Paiement"}
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                </main>
            ) : (
                /* List View */
                <main className="flex-1 p-4">
                    <div className="mb-6 space-y-4">
                        <div className="relative">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                            <input
                                type="text"
                                placeholder="Rechercher #..."
                                className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 outline-none focus:border-[#ec5b13]/50 transition-all font-bold placeholder:text-slate-600"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>

                        <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                            {orderStatusList.map((s) => (
                                <button
                                    key={s}
                                    onClick={() => setFilterStatus(orderStatusDisplayMap[s])} // Assuming filterStatus uses the display name
                                    className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-tighter transition-all whitespace-nowrap ${filterStatus === orderStatusDisplayMap[s] ? "bg-[#ec5b13] text-white shadow-lg shadow-[#ec5b13]/20" : "bg-white/5 text-slate-500"
                                        }`}
                                >
                                    {orderStatusDisplayMap[s]}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-3">
                        {isLoading && allTodayOrders.length === 0 ? (
                            <div className="flex justify-center py-20"><Spinner color="warning" /></div>
                        ) : filteredOrders.map((o) => (
                            <div
                                key={o.id}
                                onClick={() => setCurrentOrder(o)}
                                className="p-4 bg-white/5 border border-white/10 rounded-2xl active:scale-[0.98] transition-all flex justify-between items-center"
                            >
                                <div className="space-y-1">
                                    <div className="flex items-center gap-2">
                                        <span className="font-black text-lg">#{o.orderNumber}</span>
                                        <span className={`px-2 py-0.5 rounded-full text-[8px] font-bold uppercase ${getStatusColor(o.status)}`}>
                                            {orderStatusDisplayMap[o.status] || o.status}
                                        </span>
                                    </div>
                                    <p className="text-[10px] text-slate-500 font-bold uppercase">
                                        {new Date(o.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </p>
                                </div>
                                <div className="text-right flex items-center gap-3">
                                    <div>
                                        <p className="font-black text-[#ec5b13] text-lg leading-none">{formatCurrency(o.totalAmount, 'DZD')}</p>
                                        <p className="text-[9px] text-slate-500 font-bold mt-1 uppercase">{o.items?.length} article(s)</p>
                                    </div>
                                    <button
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            setOrderForDetail(o);
                                            setIsDetailModalOpen(true);
                                        }}
                                        className="p-2 bg-white/5 rounded-xl text-primary"
                                    >
                                        <Eye size={16} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </main>
            )}

            <OrderDetailModal
                isOpen={isDetailModalOpen}
                onClose={() => setIsDetailModalOpen(false)}
                order={orderForDetail}
                onRefund={async (id) => {
                    const res = await refundFullOrder({ id, returnToStock: false });
                    if (res.success) {
                        setIsDetailModalOpen(false);
                        loadOrders();
                    }
                }}
                onReplaceCode={async (orderItemId, codeId, type, reason) => {
                    const res = await replaceOrderItemCode({ orderItemId, oldCodeId: type === 'standard' ? codeId : undefined, oldSlotId: type === 'slot' ? codeId : undefined, reason });
                    if (res.success) loadOrders();
                }}
                onRefundItem={async (orderItemId, returnToStock) => {
                    const res = await refundOrderItem({ orderItemId, returnToStock });
                    if (res.success) loadOrders();
                }}
                onReprint={async () => {
                    if (!orderForDetail) return;
                    const enrichedItems = orderForDetail.items.map((it: any) => {
                        const standard = (it.fullCodes || []).map((c: any) => c.code);
                        const slots = (it.fullSlots || []).map((s: any) => `${s.parentCode} | Profil ${s.slotNumber}`);
                        return { name: it.name, quantity: it.quantity, price: it.price, codes: [...standard, ...slots], customData: it.customData, playerNickname: it.playerNickname };
                    });

                    const dataToPrint = {
                        orderNumber: orderForDetail.orderNumber,
                        date: orderForDetail.createdAt,
                        items: enrichedItems,
                        totalAmount: orderForDetail.totalAmount,
                        paymentMethod: orderForDetail.paymentMethod || "Esp├¿ces",
                        cashier: user?.nom || "Admin"
                    };

                    if (webusb.connected) {
                        try {
                            const buffer = generateOrderEscPos(dataToPrint, settings);
                            await webusb.print(buffer);
                            toast.success("R├®impression USB OK", { icon: 'ÔÜí' });
                        } catch (e) {
                            console.error("Caisse Mobile Reprini USB fail:", e);
                            toast.error("Erreur USB");
                        }
                    } else {
                        const printContent = document.getElementById('thermal-receipt-source');
                        if (printContent) {
                            toast.loading("Lancement r├®impression...", { duration: 2000 });
                            printToIframe(orderForDetail.orderNumber, printContent.innerHTML);
                        }
                    }
                }}
            />

            {/* Auto New Client Modal */}
            <Modal
                isOpen={isCreatingClient}
                onClose={() => setIsCreatingClient(false)}
                classNames={{ base: "bg-[#161616] text-white border border-[#262626]" }}
            >
                <ModalContent>
                    {(onClose) => {
                        const innerSave = async () => {
                            if (!newClientName) return;
                            try {
                                const res: any = await createClient({ nom: newClientName, telephone: newClientPhone });
                                if (res.success && res.client) {
                                    const newC = res.client;
                                    const clientsRes: any = await getAllClients({});
                                    setAllClients(Array.isArray(clientsRes) ? clientsRes : []);
                                    setSelectedClientId(newC.id);
                                    await handleEncaisser(newC.id);
                                    setIsCreatingClient(false);
                                    setNewClientName("");
                                    setNewClientPhone("");
                                }
                            } catch (e) { toast.error("Erreur creation client"); }
                        };
                        return (
                            <>
                                <ModalHeader>Nouveau Client</ModalHeader>
                                <ModalBody>
                                    <div className="space-y-4">
                                        <input
                                            className="w-full bg-black border border-white/10 rounded-xl p-3 text-sm"
                                            placeholder="Nom Complet"
                                            value={newClientName}
                                            onChange={(e) => setNewClientName(e.target.value)}
                                        />
                                        <input
                                            className="w-full bg-black border border-white/10 rounded-xl p-3 text-sm"
                                            placeholder="T├®l├®phone"
                                            value={newClientPhone}
                                            onChange={(e) => setNewClientPhone(e.target.value)}
                                        />
                                    </div>
                                </ModalBody>
                                <ModalFooter>
                                    <Button onPress={onClose} variant="flat">Ignorer</Button>
                                    <Button className="bg-[#ec5b13] text-white font-bold" onPress={innerSave}>Enregistrer & Payer</Button>
                                </ModalFooter>
                            </>
                        );
                    }}
                </ModalContent>
            </Modal>

            {/* Hidden Print Container - Standardized for Audit Reliability */}
            <div
                id="thermal-receipt-source"
                className="fixed -top-[9999px] -left-[9999px] opacity-0 pointer-events-none text-black bg-white"
                aria-hidden="true"
            >
                {printData && <ThermalReceiptV2 {...printData} />}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useMemo } from "react";
import {
    Search,
    Plus,
    MoreVertical,
    TrendingUp,
    Package,
    Wallet,
    PlusCircle,
    Settings,
    Landmark,
    Download
} from "lucide-react";
import { Button, Card, CardBody, Chip, Spinner, Dropdown, DropdownTrigger, DropdownMenu, DropdownItem, Pagination } from "@heroui/react";
import { formatCurrency } from "@/lib/formatters";
import NextImage from "next/image";
import { AddProductModal } from "@/components/admin/modals/AddProductModal";
import { AddCategoryModal } from "@/components/admin/modals/AddCategoryModal";
import { ManageCategoriesModal } from "@/components/admin/modals/ManageCategoriesModal";
import { RechargeBalanceModal } from "@/components/admin/modals/RechargeBalanceModal";
import { MassImportModal } from "@/components/admin/modals/MassImportModal";
import { useRouter, useSearchParams, usePathname } from "next/navigation";
import { deleteProductAction, toggleProductStatusAction } from "@/app/admin/catalogue/actions";
import { toast } from "react-hot-toast";

export default function CatalogueMobile({
    initialProducts,
    suppliers,
    categories,
    initialTotal,
    initialTotalPages,
    initialPage,
    initialSearch,
    initialCategoryId,
    initialStatus
}: any) {
    const router = useRouter();
    const searchParams = useSearchParams();
    const pathname = usePathname();

    const [activeTab, setActiveTab] = useState<string>(initialCategoryId || "all");
    const [filterStatus, setFilterStatus] = useState<string>(initialStatus || "all");
    const [searchTerm, setSearchTerm] = useState(initialSearch);
    const [isAddProductOpen, setIsAddProductOpen] = useState(false);
    const [productToEdit, setProductToEdit] = useState<any>(null);
    const [isAddCategoryOpen, setIsAddCategoryOpen] = useState(false);
    const [categoryToEdit, setCategoryToEdit] = useState<any>(null);
    const [isManageCategoriesOpen, setIsManageCategoriesOpen] = useState(false);
    const [isRechargeOpen, setIsRechargeOpen] = useState(false);
    const [selectedSupplier, setSelectedSupplier] = useState<any>(null);
    const [isMassImportOpen, setIsMassImportOpen] = useState(false);
    const [selectedProductForImport, setSelectedProductForImport] = useState<any>(null);

    const EXCHANGE_RATE_USD_DZD = 245;

    const updateParams = (newParams: Record<string, string | number | null>) => {
        const params = new URLSearchParams(searchParams.toString());
        Object.entries(newParams).forEach(([key, value]) => {
            if (value === null || value === "all" || value === "") params.delete(key);
            else params.set(key, value.toString());
        });
        if (!newParams.page) params.delete("page");
        router.push(`${pathname}?${params.toString()}`);
    };

    const handleEditProduct = (p: any) => {
        setProductToEdit(p);
        setIsAddProductOpen(true);
    };

    const handleDeleteProduct = async (id: number) => {
        if (confirm("Supprimer ce produit ?")) {
            const res = await deleteProductAction({ id });
            if (res.success) {
                toast.success("Supprim├®");
                router.refresh();
            }
        }
    };

    const handleToggleStatus = async (id: number, currentStatus: string) => {
        const newStatus = currentStatus === "ACTIVE" ? "ARCHIVED" : "ACTIVE";
        const res = await toggleProductStatusAction({ id, status: newStatus });
        if (res.success) {
            toast.success("Statut mis ├á jour");
            router.refresh();
        }
    };

    const handleEditCategory = (cat: any) => {
        setCategoryToEdit(cat);
        setIsManageCategoriesOpen(false);
        setIsAddCategoryOpen(true);
    };

    const handleExportCSV = () => {
        const headers = ["Produit", "Cat├®gorie", "Prix d'achat (Moyen)", "Prix de vente", "Marge", "Statut"];
        const rows = filteredVariants.map((v: any) => [
            `${v.product.name} - ${v.name}`,
            v.product.category?.name || "N/A",
            parseFloat(v.purchasePrice).toFixed(2),
            parseFloat(v.salePriceDzd).toFixed(2),
            (parseFloat(v.salePriceDzd) - parseFloat(v.purchasePrice)).toFixed(2),
            v.product.status
        ]);

        const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        const url = URL.createObjectURL(blob);
        link.setAttribute("href", url);
        link.setAttribute("download", `catalogue_export_${new Date().toISOString().split('T')[0]}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const allVariants = useMemo(() => {
        return initialProducts.flatMap((p: any) =>
            p.variants.map((v: any) => ({ ...v, product: p }))
        );
    }, [initialProducts]);

    const filteredVariants = useMemo(() => {
        return allVariants.filter((v: any) => {
            const matchesSearch = v.product.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                v.name.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesCatalog = activeTab === "all" || v.product.categoryId === parseInt(activeTab);
            const matchesStatus = filterStatus === "all" || v.product.status === filterStatus; // Assuming status is on product
            return matchesSearch && matchesCatalog && matchesStatus;
        });
    }, [allVariants, searchTerm, activeTab, filterStatus]);

    const avgProfit = useMemo(() => {
        const valid = filteredVariants.filter((v: any) => parseFloat(v.purchasePrice) > 0);
        if (valid.length === 0) return 0;
        return valid.reduce((acc: number, v: any) => acc + (parseFloat(v.salePriceDzd) - parseFloat(v.purchasePrice)), 0) / valid.length;
    }, [filteredVariants]);

    const filteredProducts = useMemo(() => {
        return initialProducts.filter((p: any) => {
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
            const matchesCategory = activeTab === "all" || p.categoryId === parseInt(activeTab);
            const matchesStatus = filterStatus === "all" || p.status === filterStatus;
            return matchesSearch && matchesCategory && matchesStatus;
        });
    }, [initialProducts, searchTerm, activeTab, filterStatus]);

    return (
        <div className="flex flex-col gap-6 pb-20 bg-[#0a0a0a] text-white min-h-screen">
            {/* Header / Tabs */}
            <header className="p-4 border-b border-white/5 space-y-4">
                <div className="flex justify-between items-center">
                    <h1 className="text-xl font-black text-white">Catalogue</h1>
                    <div className="flex gap-2">
                        <Button isIconOnly size="sm" variant="flat" className="bg-white/5" onPress={() => setIsManageCategoriesOpen(true)}>
                            <Settings size={16} />
                        </Button>
                        <Button isIconOnly size="sm" variant="flat" className="bg-primary/20 text-primary" onPress={() => setIsAddProductOpen(true)}>
                            <Plus size={16} />
                        </Button>
                    </div>
                </div>

                <div className="flex gap-2">
                    <div className="relative flex-1">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                        <input
                            type="text"
                            placeholder="Chercher un produit..."
                            className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 outline-none focus:border-primary/50 transition-all font-bold placeholder:text-slate-600"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <Button isIconOnly variant="flat" className="bg-white/5 text-slate-400" onPress={handleExportCSV}>
                        <Download size={18} />
                    </Button>
                </div>
            </header>

            {/* Suppliers Quick View */}
            <section className="px-4">
                <div className="flex items-center gap-2 mb-4 px-1">
                    <Landmark size={14} className="text-primary" />
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500">Soldes Fournisseurs</h3>
                </div>
                <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar">
                    {/* Profit Summary Card */}
                    <div className="min-w-[140px] p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-3xl space-y-1">
                        <p className="text-[9px] font-bold text-emerald-500 uppercase">Marge Moyenne</p>
                        <p className="text-sm font-black text-emerald-400">
                            {formatCurrency(avgProfit, 'DZD')}
                        </p>
                    </div>

                    {suppliers.map((s: any) => {
                        const bal = parseFloat(s.balance || "0");
                        const isLow = bal < 100 && s.currency === 'USD';
                        return (
                            <button
                                key={s.id}
                                onClick={() => {
                                    setSelectedSupplier(s);
                                    setIsRechargeOpen(true);
                                }}
                                className="min-w-[140px] p-4 bg-[#161616] border border-white/5 rounded-3xl space-y-1 text-left active:scale-95 transition-all"
                            >
                                <p className="text-[9px] font-bold text-slate-500 uppercase truncate">{s.name}</p>
                                <p className={`text-sm font-black ${isLow ? 'text-red-500' : 'text-white'}`}>
                                    {formatCurrency(bal, s.currency || 'DZD')}
                                </p>
                            </button>
                        );
                    })}
                </div>
            </section>

            {/* Filters Section */}
            <section className="px-4 space-y-4">
                <div className="flex gap-2 overflow-x-auto no-scrollbar">
                    <button
                        onClick={() => updateParams({ categoryId: "all" })}
                        className={`px-4 py-2 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all ${initialCategoryId === "all" || !initialCategoryId ? "bg-primary text-white shadow-lg shadow-primary/20" : "bg-white/5 text-slate-400"}`}
                    >
                        Tout Categories
                    </button>
                    {categories.map((c: any) => (
                        <button
                            key={c.id}
                            onClick={() => updateParams({ categoryId: c.id })}
                            className={`px-4 py-2 border border-white/5 rounded-full text-[10px] font-bold uppercase whitespace-nowrap transition-all ${initialCategoryId === c.id.toString() ? "bg-primary text-white shadow-lg shadow-primary/20" : "bg-white/5 text-slate-400"}`}
                        >
                            {c.name}
                        </button>
                    ))}
                </div>

                <div className="flex gap-2 overflow-x-auto no-scrollbar">
                    <button
                        onClick={() => updateParams({ status: "all" })}
                        className={`px-4 py-2 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all ${initialStatus === "all" || !initialStatus ? "bg-[#ec5b13]/20 text-[#ec5b13] border border-[#ec5b13]/30" : "bg-white/5 text-slate-500"}`}
                    >
                        Tous Statuts
                    </button>
                    <button
                        onClick={() => updateParams({ status: "ACTIVE" })}
                        className={`px-4 py-2 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all ${initialStatus === "ACTIVE" ? "bg-emerald-500/20 text-emerald-500 border border-emerald-500/30" : "bg-white/5 text-slate-500"}`}
                    >
                        En Vente
                    </button>
                    <button
                        onClick={() => updateParams({ status: "ARCHIVED" })}
                        className={`px-4 py-2 rounded-full text-[10px] font-black uppercase whitespace-nowrap transition-all ${initialStatus === "ARCHIVED" ? "bg-red-500/20 text-red-500 border border-red-500/30" : "bg-white/5 text-slate-500"}`}
                    >
                        Archiv├®s
                    </button>
                </div>
            </section>

            {/* Product List */}
            <section className="px-4 space-y-3">
                <div className="flex justify-between items-center px-1">
                    <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500">{filteredProducts.length} Produits</h3>
                </div>

                <div className="grid gap-3">
                    {filteredProducts.map((p: any) => {
                        const minPrice = p.variants?.length > 0
                            ? Math.min(...p.variants.map((v: any) => Number(v.salePriceDzd)))
                            : 0;

                        return (
                            <div key={p.id} className="p-3 bg-[#161616] border border-white/5 rounded-[2rem] flex items-center justify-between active:scale-[0.98] transition-all">
                                <div className="flex items-center gap-4">
                                    <div className="size-14 rounded-2xl bg-white/5 overflow-hidden flex items-center justify-center border border-white/5">
                                        {p.imageUrl ? (
                                            <img src={p.imageUrl} alt={p.name} className="w-full h-full object-cover" />
                                        ) : (
                                            <Package size={24} className="text-slate-700" />
                                        )}
                                    </div>
                                    <div className="space-y-1">
                                        <div className="flex items-center gap-2">
                                            <p className="text-sm font-black text-white">{p.name}</p>
                                            <Chip size="sm" variant="dot" color={p.status === 'ACTIVE' ? 'success' : 'danger'} className="text-[8px] h-4 border-none p-0 capitalize">
                                                {p.status}
                                            </Chip>
                                        </div>
                                        <p className="text-xs font-bold text-primary">{formatCurrency(minPrice, 'DZD')}</p>
                                    </div>
                                </div>
                                <Dropdown classNames={{ content: "bg-[#161616] border border-[#262626]" }}>
                                    <DropdownTrigger>
                                        <Button isIconOnly size="sm" variant="light" className="text-slate-600">
                                            <MoreVertical size={16} />
                                        </Button>
                                    </DropdownTrigger>
                                    <DropdownMenu aria-label="Actions" className="text-white">
                                        <DropdownItem key="edit" onPress={() => handleEditProduct(p)}>Modifier</DropdownItem>
                                        <DropdownItem key="stock" onPress={() => { setSelectedProductForImport(p); setIsMassImportOpen(true); }}>G├®rer Stock</DropdownItem>
                                        <DropdownItem key="status" onPress={() => handleToggleStatus(p.id, p.status)}>
                                            {p.status === "ACTIVE" ? "Archiver" : "R├®activer"}
                                        </DropdownItem>
                                        <DropdownItem key="delete" className="text-red-500" onPress={() => handleDeleteProduct(p.id)}>Supprimer</DropdownItem>
                                    </DropdownMenu>
                                </Dropdown>
                            </div>
                        );
                    })}
                </div>

                {initialTotalPages > 1 && (
                    <div className="flex flex-col items-center gap-4 pt-6 pb-4">
                        <Pagination
                            total={initialTotalPages}
                            page={initialPage}
                            onChange={(page) => updateParams({ page })}
                            classNames={{
                                wrapper: "gap-1",
                                item: "bg-white/5 text-slate-400 font-bold border-none",
                                cursor: "bg-primary text-white font-black",
                            }}
                        />
                        <p className="text-[10px] font-black uppercase tracking-widest text-slate-600">
                            Page {initialPage} sur {initialTotalPages}
                        </p>
                    </div>
                )}
            </section>

            <AddProductModal
                isOpen={isAddProductOpen}
                onClose={() => { setIsAddProductOpen(false); setProductToEdit(null); }}
                categories={categories}
                suppliers={suppliers}
                productToEdit={productToEdit}
            />

            <AddCategoryModal
                isOpen={isAddCategoryOpen}
                onClose={() => { setIsAddCategoryOpen(false); setCategoryToEdit(null); }}
                categoryToEdit={categoryToEdit}
            />

            <ManageCategoriesModal
                isOpen={isManageCategoriesOpen}
                onClose={() => setIsManageCategoriesOpen(false)}
                categories={categories}
                onEdit={handleEditCategory}
            />

            <MassImportModal
                isOpen={isMassImportOpen}
                onClose={() => { setIsMassImportOpen(false); setSelectedProductForImport(null); }}
                product={selectedProductForImport}
            />

            {selectedSupplier && (
                <RechargeBalanceModal
                    isOpen={isRechargeOpen}
                    onClose={() => { setIsRechargeOpen(false); setSelectedSupplier(null); }}
                    supplierId={selectedSupplier.id}
                    supplierName={selectedSupplier.name}
                    currentBalance={selectedSupplier.balance || "0"}
                    exchangeRate={EXCHANGE_RATE_USD_DZD.toString()}
                    baseCurrency={selectedSupplier.currency || 'USD'}
                />
            )}
        </div>
    );
}

"use client";

import React from "react";
import {
    User,
    Shield,
    Palette,
    Store,
    Bell,
    LogOut,
    ChevronRight,
    Smartphone,
    CreditCard,
    Users,
    KeyRound,
    Group,
    UserCircle,
    Truck,
    Headset,
    LayoutDashboard,
    ShieldAlert,
    Power,
    Globe,
    Lock,
    Save,
    Percent,
    Coins,
    Building2,
    Trash2,
    Download,
    AlertTriangle,
    RefreshCw,
    History,
    Zap,
    Brain,
    FileJson,
    FileSpreadsheet,
    Loader2
} from "lucide-react";
import { useAuthStore } from "@/store/useAuthStore";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { toast } from "react-hot-toast";
import { useSettingsStore } from "@/store/useSettingsStore";
import {
    getUsersAction,
    deleteUserAction,
    getShopSettingsAction,
    saveShopSettingsAction,
    generateMfaSecretAction,
    enableMfaAction,
    disableMfaAction,
    resetProductionDataAction,
    exportDatabaseAction,
    getAuditLogsAction,
    exportAuditLogsAction,
    generateBackupCodesAction,
    testN8nAction
} from "./actions";
import { uploadImage } from "@/app/admin/actions/upload";
import { AddMemberModal } from "@/components/admin/modals/AddMemberModal";
import { EditMemberModal } from "@/components/admin/modals/EditMemberModal";
import { Spinner, Button, Card, CardBody, Input, Textarea, Switch } from "@heroui/react";
import { ReceiptSettings } from "@/components/admin/settings/ReceiptSettings";
import { QRCodeSVG } from "qrcode.react";
import PushNotificationManager from "@/components/admin/push/PushNotificationManager";

export default function SettingsMobile() {
    const clearAuth = useAuthStore((state) => state.clearAuth);
    const user = useAuthStore((state) => state.user);
    const updateGlobalSettings = useSettingsStore((state) => state.updateSettings);
    const router = useRouter();
    const [view, setView] = React.useState<"HUB" | "TEAM" | "SHOP" | "RECEIPT" | "SECURITY" | "API" | "APPEARANCE" | "AUDIT_LOGS">("HUB");
    const [usersList, setUsersList] = React.useState<any[]>([]);
    const [isLoadingUsers, setIsLoadingUsers] = React.useState(false);
    const [isAddModalOpen, setIsAddModalOpen] = React.useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = React.useState(false);
    const [selectedMember, setSelectedMember] = React.useState<any>(null);

    // MFA State
    const [mfaQrCode, setMfaQrCode] = React.useState<string | null>(null);
    const [mfaSecret, setMfaSecret] = React.useState<string | null>(null);
    const [mfaInputCode, setMfaInputCode] = React.useState("");
    const [isMfaEnabling, setIsMfaEnabling] = React.useState(false);

    // Shop Settings State
    const [shopData, setShopData] = React.useState<any>(null);
    const [isSavingShop, setIsSavingShop] = React.useState(false);
    const [isResetting, setIsResetting] = React.useState(false);
    const [isExportingDb, setIsExportingDb] = React.useState(false);
    const [resetConfirmation, setResetConfirmation] = React.useState("");
    const [backupCodes, setBackupCodes] = React.useState<string[] | null>(null);
    const [isGeneratingCodes, setIsGeneratingCodes] = React.useState(false);

    // Audit Log States
    const [auditLogs, setAuditLogs] = React.useState<any[]>([]);
    const [isAuditLoading, setIsAuditLoading] = React.useState(false);
    const [isExportingLogs, setIsExportingLogs] = React.useState(false);

    // Appearance State & Refs
    const [isUploadingLogo, setIsUploadingLogo] = React.useState(false);
    const [isUploadingDashboardLogo, setIsUploadingDashboardLogo] = React.useState(false);
    const [isUploadingFavicon, setIsUploadingFavicon] = React.useState(false);
    const logoInputRef = React.useRef<HTMLInputElement>(null);
    const dashboardLogoInputRef = React.useRef<HTMLInputElement>(null);
    const faviconInputRef = React.useRef<HTMLInputElement>(null);

    // Additional States
    const [isTestingN8n, setIsTestingN8n] = React.useState(false);

    const loadUsers = async () => {
        setIsLoadingUsers(true);
        const res = await getUsersAction({});
        if (res.success) setUsersList(res.data as any[]);
        setIsLoadingUsers(false);
    };

    const loadShopSettings = async () => {
        const res = await getShopSettingsAction({});
        if (res.success) {
            setShopData(res.data);
            return res.data;
        }
        return null;
    };

    React.useEffect(() => {
        if (view === "TEAM") loadUsers();
        if (view === "SHOP" || view === "SECURITY" || view === "API" || view === "APPEARANCE") loadShopSettings();
        if (view === "AUDIT_LOGS") fetchAuditLogs();
    }, [view]);

    const fetchAuditLogs = async () => {
        setIsAuditLoading(true);
        try {
            const res: any = await getAuditLogsAction({});
            if (res.success) setAuditLogs(res.data || []);
        } catch (err) {
            toast.error("Erreur logs");
        } finally {
            setIsAuditLoading(false);
        }
    };

    const handleGenerateMfa = async () => {
        const res = await generateMfaSecretAction({});
        if (res.success) {
            setMfaQrCode(res.data.otpauth);
            setMfaSecret(res.data.secret);
        }
    };

    const handleEnableMfa = async () => {
        if (!mfaSecret) return;
        setIsMfaEnabling(true);
        const res = await enableMfaAction({ secret: mfaSecret, code: mfaInputCode });
        if (res.success) {
            toast.success("2FA activ├® !");
            setMfaQrCode(null);
            setMfaSecret(null);
            setMfaInputCode("");
            loadShopSettings();
        } else {
            toast.error(res.error || "Code invalide");
        }
        setIsMfaEnabling(false);
    };

    const handleDisableMfa = async () => {
        if (confirm("D├®sactiver le 2FA ?")) {
            const res = await disableMfaAction({});
            if (res.success) {
                toast.success("2FA d├®sactiv├®");
                loadShopSettings();
            }
        }
    };

    const handleGenerateBackupCodes = async () => {
        setIsGeneratingCodes(true);
        try {
            const res: any = await generateBackupCodesAction({});
            if (res.success) {
                setBackupCodes(res.data);
                toast.success("Codes de secours g├®n├®r├®s");
            }
        } catch (err) {
            toast.error("Erreur codes");
        } finally {
            setIsGeneratingCodes(false);
        }
    };

    const handleExportLogs = async (format: 'csv' | 'json') => {
        setIsExportingLogs(true);
        try {
            const res: any = await exportAuditLogsAction({});
            if (res.success) {
                const data = res.data;
                let blob;
                let filename;
                const ts = new Date().toISOString().replace(/[:.]/g, '-');
                if (format === 'json') {
                    blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                    filename = `audit_logs_${ts}.json`;
                } else {
                    const headers = "ID,User,Action,Entity,Date,IP\n";
                    const rows = data.map((l: any) => `${l.id},"${l.user?.nom || 'System'}","${l.action}","${l.entityType || ''}",${l.createdAt},${l.ipAddress}`).join("\n");
                    blob = new Blob([headers + rows], { type: 'text/csv' });
                    filename = `audit_logs_${ts}.csv`;
                }
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = filename;
                a.click();
            }
        } catch (err) {
            toast.error("Erreur export");
        } finally {
            setIsExportingLogs(false);
        }
    };

    const handleLogoFileChange = async (e: React.ChangeEvent<HTMLInputElement>, target: 'logo' | 'dashboard' | 'favicon') => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (target === 'logo') setIsUploadingLogo(true);
        else if (target === 'dashboard') setIsUploadingDashboardLogo(true);
        else if (target === 'favicon') setIsUploadingFavicon(true);

        try {
            const formData = new FormData();
            formData.append("file", file);
            const res = await uploadImage(formData);
            if (res.success && res.url) {
                if (target === 'logo') setShopData({ ...shopData, logoUrl: res.url });
                else if (target === 'dashboard') {
                    setShopData({ ...shopData, dashboardLogoUrl: res.url });
                    updateGlobalSettings({ dashboardLogoUrl: res.url });
                }
                else if (target === 'favicon') {
                    setShopData({ ...shopData, faviconUrl: res.url });
                    updateGlobalSettings({ faviconUrl: res.url });
                }
                toast.success("Image mise ├á jour");
            } else {
                toast.error("Erreur upload");
            }
        } catch (err) {
            toast.error("Erreur connexion upload");
        } finally {
            if (target === 'logo') setIsUploadingLogo(false);
            else if (target === 'dashboard') setIsUploadingDashboardLogo(false);
            else if (target === 'favicon') setIsUploadingFavicon(false);
        }
    };

    const handleTestN8n = async () => {
        setIsTestingN8n(true);
        try {
            const res = await testN8nAction({});
            if (res.success) {
                toast.success(res.message || "Test n8n r├®ussi !");
            } else {
                toast.error(res.error || "├ëchec test n8n");
            }
        } catch (err) {
            toast.error("Erreur technique n8n");
        } finally {
            setIsTestingN8n(false);
        }
    };

    const handleSaveShop = async () => {
        setIsSavingShop(true);
        const res = await saveShopSettingsAction(shopData);
        if (res.success) {
            toast.success("R├®glages enregistr├®s");
            setView("HUB");
        } else if ("error" in res) {
            toast.error(res.error || "Erreur sauvegarde");
        } else {
            toast.error("Erreur sauvegarde");
        }
        setIsSavingShop(false);
    };

    const toggleMaintenance = async (val: boolean) => {
        const res = await saveShopSettingsAction({ ...shopData, isMaintenanceMode: val });
        if (res.success) {
            setShopData({ ...shopData, isMaintenanceMode: val });
            toast.success(val ? "Maintenance Activ├®e" : "Maintenance D├®sactiv├®e");
        }
    };

    const handleDeleteUser = async (id: number) => {
        if (confirm("Supprimer ce membre ?")) {
            const res = await deleteUserAction({ id });
            if (res.success) {
                toast.success("Membre supprim├®");
                loadUsers();
            } else if ("error" in res) {
                toast.error(res.error || "Erreur suppression");
            } else {
                toast.error("Erreur suppression");
            }
        }
    };

    const handleLogout = async () => {
        await clearAuth();
        toast.success("D├®connect├®");
        router.push("/admin/login");
    };

    const handleExportDatabase = async () => {
        setIsExportingDb(true);
        try {
            const res = await exportDatabaseAction({});
            if (res.success && res.data) {
                const blob = new Blob([JSON.stringify(res.data, null, 2)], { type: 'application/json' });
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `database_backup_mobile_${new Date().toISOString().split('T')[0]}.json`;
                a.click();
                toast.success("Base de donn├®es export├®e");
            } else {
                toast.error(res.error || "Erreur export");
            }
        } catch (err) {
            toast.error("Erreur de connexion");
        } finally {
            setIsExportingDb(false);
        }
    };

    const handleProductionReset = async () => {
        if (resetConfirmation !== "PERMANENT DELETE") {
            toast.error("Veuillez saisir le texte de confirmation");
            return;
        }

        if (!confirm("EFFACER TOUTE LA PRODUCTION ? Cette action est irr├®versible.")) return;

        setIsResetting(true);
        try {
            const res = await resetProductionDataAction({ confirmation: resetConfirmation });
            if (res.success) {
                toast.success("Syst├¿me r├®initialis├®");
                setResetConfirmation("");
                window.location.reload();
            } else {
                toast.error(res.error || "Erreur reset");
            }
        } catch (err) {
            toast.error("Erreur de connexion");
        } finally {
            setIsResetting(false);
        }
    };

    const { isB2bEnabled } = useSettingsStore();

    const hubGroups = [
        {
            title: "Gestion Quotidienne",
            items: [
                { name: "Dashboard", icon: LayoutDashboard, color: "text-blue-400", bg: "bg-blue-400/10", href: "/admin", desc: "Statistiques & Revenus", roles: ["ADMIN", "CAISSIER", "TRAITEUR"] },
                { name: "Clients & Cr├®dits", icon: UserCircle, color: "text-indigo-400", bg: "bg-indigo-400/10", href: "/admin/clients", desc: "Dettes & Paiements", roles: ["ADMIN", "CAISSIER"] },
                { name: "Fournisseurs", icon: Truck, color: "text-pink-400", bg: "bg-pink-400/10", href: "/admin/fournisseurs", desc: "Balances & Flux", roles: ["ADMIN"] },
                { name: "Comptes Partag├®s", icon: Group, color: "text-orange-400", bg: "bg-orange-400/10", href: "/admin/comptes-partages", desc: "Inventaire & Slots", roles: ["ADMIN", "CAISSIER"] },
                { name: "Tickets Support", icon: Headset, color: "text-red-400", bg: "bg-red-400/10", href: "/admin/support", desc: "Plaintes & SAV", roles: ["ADMIN", "CAISSIER", "TRAITEUR"] },
            ]
        },
        {
            title: "Configuration Boutique",
            items: [
                { name: "Identit├® Boutique", icon: Store, color: "text-blue-500", bg: "bg-blue-500/10", desc: "Infos, Logos, Coordonn├®es", roles: ["ADMIN"] },
                { name: "├ëquipe & Acc├¿s", icon: Users, color: "text-[#ec5b13]", bg: "bg-[#ec5b13]/10", desc: "Membres, R├┤les, Permissions", roles: ["ADMIN"] },
                ...(isB2bEnabled ? [{ name: "B2B & Partners", icon: Smartphone, color: "text-emerald-500", bg: "bg-emerald-500/10", href: "/admin/b2b", desc: "Revendeurs, API, Tarifs", roles: ["ADMIN"] }] : []),
                { name: "Ticket de Caisse", icon: CreditCard, color: "text-amber-500", bg: "bg-amber-500/10", desc: "Logiciel de caisse, Re├ºus", roles: ["ADMIN"] },
                { name: "Apparence & Visuels", icon: Palette, color: "text-purple-400", bg: "bg-purple-400/10", desc: "Logos, Couleurs, Favicon", roles: ["ADMIN"] },
            ]
        },
        {
            title: "S├®curit├® & Syst├¿me",
            items: [
