                            if (!newName) return;
                            setIsCreatingNew(true);
                            const res = (await createClient({ nom: newName, telephone: newTel })) as { success: boolean; error?: string };
                            if (res.success) {
                                toast.success("Client cr├®├®");
                                onClose();
                                refreshData();
                                setNewName("");
                                setNewTel("");
                            } else {
                                toast.error(res.error || "Erreur cr├®ation client");
                            }
                            setIsCreatingNew(false);
                        };

                        return (
                            <>
                                <ModalHeader>Nouveau Profil Client</ModalHeader>
                                <ModalBody className="gap-4">
                                    <Input
