                                        placeholder="Ex: Karim Revendeur"
                                        value={newName}
                                        onValueChange={setNewName}
                                        classNames={{ inputWrapper: "bg-[#0a0a0a]" }}
                                    />
                                    <Input
                                        label="T├®l├®phone"
                                        placeholder="06..."
                                        value={newTel}
                                        onValueChange={setNewTel}
                                        classNames={{ inputWrapper: "bg-[#0a0a0a]" }}
                                    />
                                </ModalBody>
