                                    <Button variant="flat" onPress={onClose} className="text-slate-400">Annuler</Button>
                                    <Button
                                        isLoading={isCreatingNew}
                                        className="bg-[#ec5b13] text-white font-bold"
                                        onPress={handleSave}
                                    >
                                        Cr├®er le Profil
                                    </Button>
                                </ModalFooter>
                            </>
                        );

                    }}
                </ModalContent>
            </Modal>
        </div>
    );
}

